import{_ as e,c as a,o as t,a as o}from"./app.256ce7d8.js";const h=JSON.parse('{"title":"一些简单的拓展","description":"","frontmatter":{},"headers":[],"relativePath":"summarize/webpack4/09.expansion.md","lastUpdated":1645146678000}'),s={name:"summarize/webpack4/09.expansion.md"},p=o('<h1 id="一些简单的拓展" tabindex="-1">一些简单的拓展 <a class="header-anchor" href="#一些简单的拓展" aria-hidden="true">#</a></h1><ul><li>Scope Hoisting 作用域提升</li></ul><p>js 里面有变量提升和函数提升的概念，也就是把变量和函数的声明提升到当前作用域顶部。<code>webpack</code> 里面的作用域提升和它们类似，在某些情况下，<code>webpack</code> 会把被引入的 js 文件提升到引入者的顶部，减少创建的代码作用域，使得代码体积和内存开销变小。</p><p>构建模式是 <code>production</code> 时，<code>webpack</code> 会自动开启作用域提升，你也可以用 <code>ModuleConcatenationPlugin</code> 来手动开启。</p><p>作用域提升是针对 ESM 的，非 ESM 的情况下，<code>webpack</code> 会自动回退，不使用作用域提升。</p><ul><li>Hot Module Reload 模块热更新</li></ul><p><img src="https://p1-jj.byteimg.com/tos-cn-i-t2oaga2asx/gold-user-assets/2019/12/1/16ec13499800dfce~tplv-t2oaga2asx-watermark.awebp" alt="热更新原理图"></p><p><a href="https://juejin.im/post/6844904008432222215" target="_blank" rel="noreferrer">图源</a></p><p><img src="https://p1-jj.byteimg.com/tos-cn-i-t2oaga2asx/gold-user-assets/2019/9/2/16cf203824359397~tplv-t2oaga2asx-watermark.awebp" alt="热更新原理图"></p><p><a href="https://juejin.cn/post/6844903933157048333" target="_blank" rel="noreferrer">图源</a></p><ul><li>Tree Shaking 摇树优化</li></ul><p>使用摇树优化是为了删除一些没有被使用的代码，同样，它也是依赖于 ESM 的。</p><ul><li>Module Federation 模块联邦</li></ul><p>TODO</p>',14),c=[p];function r(i,n,l,d,_,u){return t(),a("div",null,c)}const g=e(s,[["render",r]]);export{h as __pageData,g as default};
